import * as xlsx from 'xlsx';
import * as path from 'path';

const BUILDINGS = ['25', '26', '27', '28', '38', '36', '34', '33', '37'];
const BATCHES = ['BTECH-2021', 'BTECH-2022', 'BTECH-2023', 'BTECH-2024'];
const SUBJECTS = [
  { id: 'CSE101', name: 'Intro to Programming' },
  { id: 'CSE202', name: 'Data Structures' },
  { id: 'MTH101', name: 'Calculus I' },
  { id: 'PHY102', name: 'Physics' },
  { id: 'ENG101', name: 'English' },
  { id: 'CSE301', name: 'Operating Systems' },
  { id: 'CSE302', name: 'Database Management' },
  { id: 'MTH201', name: 'Discrete Math' }
];

async function generateAdvancedSample() {
  const wb = xlsx.utils.book_new();

  // 1. Students Sheet
  const students: any[] = [];
  const prefixes = [123, 124, 125, 126];
  for (let i = 1; i <= 1000; i++) {
    const prefix = prefixes[i % prefixes.length];
    const suffix = String(i).padStart(5, '0');
    students.push({
      StudentID: `${prefix}${suffix}`,
      StudentName: `Student ${i}`,
      Batch: BATCHES[i % BATCHES.length],
      IsBYOD: i % 3 === 0 ? 'True' : 'False'
    });
  }
  xlsx.utils.book_append_sheet(wb, xlsx.utils.json_to_sheet(students), 'students');

  // 2. Infrastructure Sheet
  const rooms: any[] = [];
  BUILDINGS.forEach(bId => {
    const startFloor = bId === '37' ? 6 : 1;
    for (let f = startFloor; f <= 9; f++) {
      for (let r = 1; r <= 12; r++) {
        rooms.push({
            FullRoomNumber: `${bId}-${f}${String(r).padStart(2, '0')}`,
            Building: bId,
            Capacity: r % 4 === 0 ? 120 : (r % 2 === 0 ? 60 : 30),
            Type: r % 4 === 0 ? 'Auditorium' : 'Classroom',
            IsBYOD: r % 3 === 0 ? 'True' : 'False'
        });
      }
    }
  });
  xlsx.utils.book_append_sheet(wb, xlsx.utils.json_to_sheet(rooms), 'infrastructure');

  // 3. Faculty Sheet
  const faculty: any[] = [];
  for (let i = 1; i <= 50; i++) {
    faculty.push({
      TeacherID: `${50000 + i}`,
      TeacherName: `Professor ${i}`,
      expertise: SUBJECTS[i % SUBJECTS.length].name
    });
  }
  xlsx.utils.book_append_sheet(wb, xlsx.utils.json_to_sheet(faculty), 'faculty');

  // 4. Courses Sheet
  const courses = SUBJECTS.map(s => ({
    Subject: s.id,
    SubjectName: s.name,
    credit_hours: 4,
    session_duration_minutes: 90
  }));
  xlsx.utils.book_append_sheet(wb, xlsx.utils.json_to_sheet(courses), 'courses');

  // 5. Student Enrollment Sheet
  const enrollments: any[] = [];
  students.forEach((s, idx) => {
    const shuffled = [...SUBJECTS].sort(() => Math.random() - 0.5);
    const count = 6 + (idx % 2);
    for (let j = 0; j < count; j++) {
      enrollments.push({ StudentID: s.StudentID, Subject: shuffled[j].id });
    }
  });
  xlsx.utils.book_append_sheet(wb, xlsx.utils.json_to_sheet(enrollments), 'student_enrollment');

  // 6. Teachers-Subjects Mapping
  const ts: any[] = [];
  faculty.forEach((f, idx) => {
    // Each teacher can teach 2-3 subjects
    const s1 = SUBJECTS[idx % SUBJECTS.length];
    const s2 = SUBJECTS[(idx + 1) % SUBJECTS.length];
    ts.push({ TeacherID: f.TeacherID, SubjectCode: s1.id });
    ts.push({ TeacherID: f.TeacherID, SubjectCode: s2.id });
  });
  xlsx.utils.book_append_sheet(wb, xlsx.utils.json_to_sheet(ts), 'teacher_subjects');

  const outputPath = path.join(process.cwd(), 'lpu_production_sample.xlsx');
  xlsx.writeFile(wb, outputPath);
  console.log(`✅ Production-grade sample generated at: ${outputPath}`);
}

generateAdvancedSample();

