import multer from 'multer';
import * as xlsx from 'xlsx';
import { Request, Response } from 'express';
import { supabase } from '../config/supabase';

const upload = multer({ storage: multer.memoryStorage() });

export const setupDataRoutes = (app: any) => {
  app.post('/api/data/import', upload.single('file'), async (req: Request, res: Response) => {
    if (!req.file) {
      return res.status(400).json({ success: false, message: 'No file uploaded' });
    }

    try {
      console.log('--- Import Started ---');
      if (!req.file) throw new Error('No file in request');
      console.log('File size:', req.file.size);

      const workbook = xlsx.read(req.file.buffer, { type: 'buffer' });
      console.log('Sheets found:', workbook.SheetNames);

      const results: any = {};

      for (const sheetName of workbook.SheetNames) {
        const data = xlsx.utils.sheet_to_json(workbook.Sheets[sheetName]);
        if (data.length === 0) continue;

        console.log(`Processing ${data.length} rows from sheet: ${sheetName}`);
        console.log(`Sample data from ${sheetName}:`, JSON.stringify(data[0]));

        switch (sheetName.toLowerCase()) {
          case 'students':
            results.students = await ingestStudents(data);
            break;
          case 'infrastructure':
            results.infrastructure = await ingestInfrastructure(data);
            break;
          case 'faculty':
            results.faculty = await ingestFaculty(data);
            break;
          case 'courses':
            results.courses = await ingestCourses(data);
            break;
          case 'student enrollment':
          case 'student_enrollment':
            results.enrollments = await ingestEnrollments(data);
            break;
          case 'teachers-subjects':
          case 'teacher_subjects':
            results.teacherSubjects = await ingestTeacherSubjects(data);
            break;
          default:
            console.log(`Skipping unknown sheet: ${sheetName}`);
        }
      }

      res.json({ 
        success: true, 
        message: 'Import complete!',
        details: results
      });
    } catch (err: any) {
      console.error(err);
      res.status(500).json({ success: false, message: `Error parsing spreadsheet: ${err.message}` });
    }
  });
};

async function ingestStudents(data: any[]) {
  const mapped = data.map(s => ({
    student_id: s.StudentID || s.student_id,
    name: s.StudentName || s.name,
    program: s.program || s.Batch,
    specialization_id: s.specialization_id || s.Batch,
    minor_id: s.minor_id,
    pathway_id: s.pathway_id,
    is_byod: String(s.IsBYOD || s.is_byod).toLowerCase() === 'true',
    residence_type: s.residence_type,
    backlog_courses: s.backlog_courses ? s.backlog_courses.split(',').map((c: string) => c.trim()) : []
  }));

  console.log('Mapped student[0]:', JSON.stringify(mapped[0]));

  const { error } = await supabase.from('students').upsert(mapped, { onConflict: 'student_id' });
  if (error) throw error;
  return mapped.length;
}

async function ingestInfrastructure(data: any[]) {
  const mapped = data.map(r => ({
    room_id: r.FullRoomNumber || r.room_id,
    block_id: String(r.Building || r.block_id),
    capacity_lecture: Number(r.Capacity || r.capacity_lecture),
    room_type: r.Type || r.room_type,
    is_byod_ready: String(r.IsBYOD || r.is_byod_ready).toLowerCase() === 'true',
    connected_blocks: r.connected_blocks ? r.connected_blocks.split(',').map((b: string) => b.trim()) : []
  }));

  const { error } = await supabase.from('infrastructure').upsert(mapped, { onConflict: 'room_id' });
  if (error) throw error;
  return mapped.length;
}

async function ingestFaculty(data: any[]) {
  const mapped = data.map(f => ({
    teacher_id: f.TeacherID || f.teacher_id,
    name: f.TeacherName || f.name,
    department_id: f.department_id || 'GENERAL',
    expertise_tags: f.expertise_tags ? f.expertise_tags.split(',').map((t: string) => t.trim()) : [],
    max_teaching_hours_day: Number(f.max_teaching_hours_day || 6),
    forbidden_slots: f.forbidden_slots ? JSON.parse(f.forbidden_slots) : [],
    travel_tolerance_mins: Number(f.travel_tolerance_mins || 0)
  }));

  const { error } = await supabase.from('faculty').upsert(mapped, { onConflict: 'teacher_id' });
  if (error) throw error;
  return mapped.length;
}

async function ingestCourses(data: any[]) {
  const mapped = data.map(c => ({
    course_id: String(c.Subject || c.course_id),
    course_name: c.name || c.SubjectName || c.course_name,
    credit_hours: Number(c.credit_hours || 0),
    course_type: c.course_type || 'Lecture',
    required_equipment: c.required_equipment ? JSON.parse(c.required_equipment) : [],
    session_duration_minutes: Number(c.session_duration_minutes || 90)
  }));

  const { error } = await supabase.from('courses').upsert(mapped, { onConflict: 'course_id' });
  if (error) throw error;
  return mapped.length;
}

async function ingestEnrollments(data: any[]) {
  const mapped = data.map(e => ({
    student_id: String(e.StudentID || e.student_id),
    course_id: String(e.Subject || e.course_id),
    semester: e.semester || 'Fall 2024'
  }));

  const { error } = await supabase.from('student_enrollments').upsert(mapped, { onConflict: 'student_id, course_id' });
  if (error) throw error;
  return mapped.length;
}

async function ingestTeacherSubjects(data: any[]) {
  const mapped = data.map(ts => ({
    teacher_id: String(ts.TeacherID || ts.teacher_id),
    course_id: String(ts.SubjectCode || ts.course_id)
  }));

  const { error } = await supabase.from('teacher_subjects').upsert(mapped, { onConflict: 'teacher_id, course_id' });
  if (error) throw error;
  return mapped.length;
}

import { supabase } from '../config/supabase';

interface Section {
  id: string;
  courseId: string;
  type: 'Lecture' | 'Lab';
  capacity: number;
  enrolledStudents: string[];
  sessionsPerWeek: number;
  teacherId?: string;
}

interface Room {
  id: string;
  building: string;
  capacity: number;
  type: string;
  isByodReady: boolean;
}

interface Assignment {
  course_code: string;
  section_name: string;
  time_slot: string;
  room_id: string;
  instructor_name: string;
  student_ids: string[];
}

export class SolverService {
  private rooms: Room[] = [];
  private sections: Section[] = [];
  private teachers: any[] = [];
  private teacherCourseMap: Record<string, string[]> = {}; // courseId -> teacherIds

  async loadData() {
    // 1. Fetch Infrastructure
    const { data: roomsData } = await supabase.from('infrastructure').select('*');
    this.rooms = (roomsData || []).map(r => ({
      id: r.room_id,
      building: r.block_id,
      capacity: r.capacity_lecture,
      type: r.room_type,
      isByodReady: r.is_byod_ready
    }));

    // 2. Fetch Faculty & Mappings
    const { data: facultyData } = await supabase.from('faculty').select('*');
    const { data: mappingData } = await supabase.from('teacher_subjects').select('*');

    this.teachers = facultyData || [];
    this.teacherCourseMap = {};
    (mappingData || []).forEach(m => {
      if (!this.teacherCourseMap[m.course_id]) this.teacherCourseMap[m.course_id] = [];
      this.teacherCourseMap[m.course_id].push(m.teacher_id);
    });

    // 3. Fetch Courses & Enrollments
    const { data: coursesData } = await supabase.from('courses').select('*');
    const { data: enrollmentsData } = await supabase.from('student_enrollments').select('*');

    // 4. Group enrollments by course
    const enrollmentMap: Record<string, string[]> = {};
    (enrollmentsData || []).forEach(e => {
      if (!enrollmentMap[e.course_id]) enrollmentMap[e.course_id] = [];
      enrollmentMap[e.course_id].push(e.student_id);
    });

    // 5. Build Sections
    this.sections = (coursesData || []).flatMap(c => {
      const students = enrollmentMap[c.course_id] || [];
      const sectionCount = Math.ceil(students.length / 60) || 1;
      const chunks = [];
      for (let i = 0; i < students.length; i += 60) {
        chunks.push(students.slice(i, i + 60));
      }

      // Sessions per week based on credits (Rule: 1 credit = 1 session/week, min 1)
      const sessions = Math.max(1, Number(c.credit_hours || 1));

      return chunks.map((chunk, idx) => ({
        id: `${c.course_id}-S${idx + 1}`,
        courseId: c.course_id,
        type: 'Lecture',
        capacity: 60,
        enrolledStudents: chunk,
        sessionsPerWeek: sessions
      }));
    });
  }

  async runSolver() {
    console.log(`Starting Advanced Weekly Solver...`);
    console.log(`- Sections: ${this.sections.length}`);
    console.log(`- Rooms: ${this.rooms.length}`);

    const assignments: Assignment[] = [];

    // Conflict Matrices
    const roomOccupied: Set<string> = new Set(); // room_id|day|slot
    const teacherOccupied: Set<string> = new Set(); // teacher_id|day|slot
    const studentOccupied: Set<string> = new Set(); // student_id|day|slot

    const timeSlots = [
      '09:00 AM - 10:30 AM', '10:30 AM - 12:00 PM', '12:00 PM - 01:30 PM',
      '01:30 PM - 03:00 PM', '03:00 PM - 04:30 PM', '04:30 PM - 06:00 PM'
    ];
    const days = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri'];

    let totalSessionsPlaced = 0;
    let conflictsAvoided = 0;

    for (const section of this.sections) {
      // Find qualified teachers for this course
      const qualifiedTeacherIds = this.teacherCourseMap[section.courseId] || [];
      const teacherCandidates = this.teachers.filter(t => qualifiedTeacherIds.includes(t.teacher_id));

      // Fallback to random teacher if no qualified mapping exists (production data check)
      const assignedTeacher = teacherCandidates.length > 0 
        ? teacherCandidates[Math.floor(Math.random() * teacherCandidates.length)]
        : this.teachers[Math.floor(Math.random() * this.teachers.length)];

      for (let s = 0; s < section.sessionsPerWeek; s++) {
        let sessionAssigned = false;

        // Shuffle days/slots to distribute load
        const shuffledDays = [...days].sort(() => Math.random() - 0.5);
        const shuffledSlots = [...timeSlots].sort(() => Math.random() - 0.5);

        // Room selection heuristic (smallest fitting room)
        const compatibleRooms = this.rooms
          .filter(r => r.capacity >= section.enrolledStudents.length)
          .sort((a, b) => a.capacity - b.capacity);

        for (const room of compatibleRooms) {
          for (const day of shuffledDays) {
            for (const slot of shuffledSlots) {
              const timeKey = `${day} ${slot}`;
              const roomKey = `${room.id}|${timeKey}`;
              const teacherKey = `${assignedTeacher?.teacher_id}|${timeKey}`;

              // 1. Room Check
              if (roomOccupied.has(roomKey)) continue;

              // 2. Teacher Check
              if (assignedTeacher && teacherOccupied.has(teacherKey)) {
                conflictsAvoided++;
                continue;
              }

              // 3. Student Check (All students must be free)
              let studentConflict = false;
              for (const studentId of section.enrolledStudents) {
                if (studentOccupied.has(`${studentId}|${timeKey}`)) {
                  studentConflict = true;
                  break;
                }
              }
              if (studentConflict) {
                conflictsAvoided++;
                continue;
              }

              // All checks passed! Assign.
              assignments.push({
                course_code: section.courseId,
                section_name: section.id,
                time_slot: timeKey,
                room_id: room.id,
                instructor_name: assignedTeacher?.name || 'Staff',
                student_ids: section.enrolledStudents
              });

              // Mark as busy
              roomOccupied.add(roomKey);
              if (assignedTeacher) teacherOccupied.add(teacherKey);
              for (const studentId of section.enrolledStudents) {
                studentOccupied.add(`${studentId}|${timeKey}`);
              }

              sessionAssigned = true;
              totalSessionsPlaced++;
              break;
            }
            if (sessionAssigned) break;
          }
          if (sessionAssigned) break;
        }

        if (!sessionAssigned) {
          console.warn(`⚠️ Failed to place session ${s+1} for section ${section.id}`);
        }
      }
    }

    console.log(`✅ Solver Finished.`);
    console.log(`- Sessions Placed: ${totalSessionsPlaced}`);
    console.log(`- Conflicts Avoided: ${conflictsAvoided}`);

    // Persist Results
    // Use a column that exists (room_id) and a filter that matches all (not equal to 'FORCE_CLEAR')
    console.log('Finalizing: Persisting assignments to Database...');
    const { error: delError } = await supabase.from('master_timetable').delete().neq('room_id', 'FORCE_CLEAR');
    if (delError) console.error('Delete error:', delError);

    // Batch Insert (Chunked for Supabase limits)
    for (let i = 0; i < assignments.length; i += 500) {
      const chunk = assignments.slice(i, i + 500);
      const { error } = await supabase.from('master_timetable').insert(chunk);
      if (error) {
        console.error('Persistence error during insert:', error);
      } else {
        console.log(`Inserted batch of ${chunk.length} assignments.`);
      }
    }

    return totalSessionsPlaced;
  }
}

import { supabase } from '../config/supabase';
import { RoomData, StudentData, CourseData, TravelTimeData } from '../translators/xmlGenerator';

export async function fetchRooms(): Promise<RoomData[]> {
  const { data, error } = await supabase
    .from('infrastructure')
    .select('*');

  if (error) throw error;

  return data.map(r => ({
    id: r.room_id,
    building: r.block_id,
    roomNumber: r.room_id,
    capacity: r.capacity_lecture,
    type: r.room_type,
    features: r.is_byod_ready ? ['BYOD_READY'] : []
  }));
}

export async function fetchStudents(): Promise<StudentData[]> {
  const { data, error } = await supabase
    .from('students')
    .select('*');

  if (error) throw error;

  return data.map(s => ({
    externalId: s.student_id,
    name: s.name,
    major: s.specialization_id || 'GENERAL',
    minor: s.minor_id,
    byod: s.is_byod
  }));
}

export async function fetchTravelTimes(): Promise<TravelTimeData[]> {
  const { data, error } = await supabase
    .from('infrastructure')
    .select('block_id, connected_blocks');

  if (error) throw error;

  // This is a naive expansion, ideally we have a dedicated table for travel matrix
  // For now, mapping LPU Connected_Blocks Rule
  const travels: TravelTimeData[] = [];
  data.forEach((r: any) => {
    r.connected_blocks?.forEach((adj: string) => {
      travels.push({ block1: r.block_id, block2: adj, isAdjacent: true });
    });
  });

  return travels;
}

export async function fetchCourses(): Promise<CourseData[]> {
  const { data, error } = await supabase
    .from('courses')
    .select('*');

  if (error) throw error;

  // For simplicity, generate 2 sections per course for now (1 Lecture, 1 Lab)
  // In real use, sections might be in a separate table
  return data.map(c => ({
    id: c.course_id,
    subject: c.course_id.substring(0, 3).toUpperCase(),
    courseNumber: c.course_id.substring(3),
    sections: [
      { id: `${c.course_id}-L1`, capacity: 60, type: 'Lecture', minutesPerWeek: c.session_duration_minutes },
      { id: `${c.course_id}-P1`, capacity: 30, type: 'Lab', minutesPerWeek: c.session_duration_minutes }
    ]
  }));
}

export async function fetchStats() {
  const [students, infrastructure, courses] = await Promise.all([
    supabase.from('students').select('student_id', { count: 'exact', head: true }),
    supabase.from('infrastructure').select('room_id', { count: 'exact', head: true }),
    supabase.from('courses').select('course_id', { count: 'exact', head: true })
  ]);

  return {
    totalStudents: students.count || 0,
    totalRooms: infrastructure.count || 0,
    totalCourses: courses.count || 0,
    solverStatus: 'IDLE',
    lastGenerated: new Date().toISOString()
  };
}

