import { supabase } from '../config/supabase';

async function cleanup() {
  console.log('⏳ Clearing tables via Supabase API...');

  try {
    const tables = [
      'student_enrollments', 
      'teacher_subjects', 
      'master_timetable', 
      'students', 
      'infrastructure', 
      'faculty', 
      'courses'
    ];

    for (const table of tables) {
      console.log(`Clearing ${table}...`);

      const { error } = await supabase.from(table).delete().neq('id', '00000000-0000-0000-0000-000000000000');

      if (error && error.code !== '42703') { // Ignore error if 'id' column doesn't exist (some tables use student_id)
        // Fallback for tables without 'id' column
        const idCol = table === 'students' ? 'student_id' : 
                      table === 'infrastructure' ? 'room_id' : 
                      table === 'faculty' ? 'teacher_id' : 
                      table === 'courses' ? 'course_id' : 'student_id';

        await supabase.from(table).delete().neq(idCol, 'FORCE_DELETE');
      }

      console.log(`✅ ${table} cleared.`);
    }

    console.log('🎉 Database cleanup attempt finished.');

  } catch (err: any) {
    console.error('❌ Cleanup failed:', err.message);
  }
}

cleanup();

