import { useState, useEffect } from 'react';
import { Search, Filter, Calendar as CalendarIcon, Loader2, User, BookOpen, Home, FileUp } from 'lucide-react';

export default function TimetableView() {
  const [schedule, setSchedule] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [viewType, setViewType] = useState<'master' | 'student' | 'teacher' | 'room'>('student');
  const [searchId, setSearchId] = useState('');
  const [directory, setDirectory] = useState<any[]>([]);
  const [showDir, setShowDir] = useState(false);

  useEffect(() => {
    if (!searchId && viewType !== 'master') {
      fetchDirectory();
      setShowDir(true);
    } else {
      setShowDir(false);
      fetchSchedule();
    }
  }, [viewType, searchId]);

  const fetchDirectory = () => {
    setLoading(true);
    fetch(`http://localhost:4000/api/directory/${viewType}s`)
      .then(res => res.json())
      .then(data => {
        setDirectory(data);
        setLoading(false);
      })
      .catch(err => {
        console.error(err);
        setLoading(false);
      });
  };

  const fetchSchedule = () => {
    setLoading(true);
    let url = 'http://localhost:4000/api/solver/solution';
    if (viewType !== 'master' && searchId) {
      url += `/${viewType}/${searchId}`;
    }

    fetch(url)
      .then(res => res.json())
      .then(data => {
        setSchedule(Array.isArray(data) ? data : []);
        setLoading(false);
      })
      .catch(err => {
        console.error(err);
        setLoading(false);
      });
  };

  return (
    <div className="view-container">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
        <h1 style={{ fontSize: '2rem', fontWeight: 800 }}>Scheduling Matrix</h1>
        <div style={{ display: 'flex', gap: '1rem' }}>
          <div style={{ display: 'flex', backgroundColor: 'rgba(255,255,255,0.05)', borderRadius: '8px', padding: '0.25rem' }}>
             <TabButton active={viewType === 'master'} onClick={() => { setViewType('master'); setSearchId(''); }} icon={<BookOpen size={16}/>} label="Master" />
             <TabButton active={viewType === 'student'} onClick={() => { setViewType('student'); setSearchId(''); }} icon={<User size={16}/>} label="Student" />
             <TabButton active={viewType === 'teacher'} onClick={() => { setViewType('teacher'); setSearchId(''); }} icon={<User size={16}/>} label="Teacher" />
             <TabButton active={viewType === 'room'} onClick={() => { setViewType('room'); setSearchId(''); }} icon={<Home size={16}/>} label="Room" />
          </div>
        </div>
      </div>

      <div style={{ display: 'flex', gap: '1rem', marginBottom: '2rem' }}>
          <div className="glass-card" style={{ flex: 1, padding: '0.75rem 1rem', display: 'flex', gap: '0.5rem', alignItems: 'center' }}>
            <Search size={18} style={{ color: 'var(--text-dim)' }} />
            <input 
                type="text" 
                placeholder={viewType === 'master' ? "Search all classes..." : `Enter ${viewType} ID (e.g. 12300001, 50001, 25-102)...`}
                value={searchId}
                onChange={(e) => setSearchId(e.target.value)}
                style={{ backgroundColor: 'transparent', border: 'none', color: 'white', outline: 'none', width: '100%' }} 
            />
          </div>
          <button className="btn-secondary" onClick={() => { setSearchId(''); fetchDirectory(); }} style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
            <Filter size={18} /> Clear
          </button>
          <button className="btn-primary" onClick={() => alert('Excel Export Triggered!')} style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
            <FileUp size={18} /> Export
          </button>
      </div>

      {loading ? (
        <div className="glass-card" style={{ padding: '4rem', textAlign: 'center', color: 'var(--text-dim)' }}>
          <Loader2 size={48} className="animate-spin" style={{ margin: '0 auto 1rem' }} />
          <p>Processing request...</p>
        </div>
      ) : showDir ? (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '1.5rem' }}>
          {directory.map((item, idx) => (
            <div 
              key={idx} 
              className="glass-card" 
              onClick={() => setSearchId(item.student_id || item.teacher_id || item.room_id)}
              style={{ cursor: 'pointer', padding: '1.5rem', border: '1px solid var(--border)' }}
            >
              <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                <div style={{ 
                  width: '40px', 
                  height: '40px', 
                  borderRadius: '10px', 
                  backgroundColor: 'var(--primary-glow)', 
                  color: 'var(--primary)',
                  display: 'flex',
                  alignItems: 'center',
                 …506 chars truncated…m.block_id}</div>
                </div>
              </div>
            </div>
          ))}
          {directory.length === 0 && (
             <div className="glass-card" style={{ gridColumn: '1 / -1', padding: '4rem', textAlign: 'center', color: 'var(--text-dim)' }}>
                No records found in this category.
             </div>
          )}
        </div>
      ) : (
        <div className="glass-card" style={{ padding: 0, overflow: 'hidden' }}>
          <div style={{ padding: '1rem' }}>
            {['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(day => {
              const dayClasses = schedule
                .filter(item => (item.time || item.time_slot).startsWith(day))
                .sort((a, b) => {
                  const parseTime = (tStr: string) => {
                    const [time, modifier] = tStr.split(' ');
                    let [hours, minutes] = time.split(':').map(Number);
                    if (modifier === 'PM' && hours !== 12) hours += 12;
                    if (modifier === 'AM' && hours === 12) hours = 0;
                    return hours * 60 + minutes;
                  };
                  const timeA = parseTime((a.time || a.time_slot).split(' ').slice(1, 3).join(' '));
                  const timeB = parseTime((b.time || b.time_slot).split(' ').slice(1, 3).join(' '));
                  return timeA - timeB;
                });

              return (
                <div key={day} style={{ marginBottom: '2rem' }}>
                  <h3 style={{ 
                    padding: '0.5rem 1rem', 
                    backgroundColor: 'rgba(255,255,255,0.05)', 
                    borderRadius: '6px',
                    color: 'var(--primary)',
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'center'
                  }}>
                    {day === 'Sat' ? `${day} (Reserve/Makeup)` : day}
                    <span style={{ fontSize: '0.8rem', color: 'var(--text-dim)' }}>{dayClasses.length} Sessions</span>
                  </h3>

                  {dayClasses.length > 0 ? (
                    <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left', marginTop: '0.5rem' }}>
                      <thead>
                        <tr style={{ color: 'var(--text-dim)', fontSize: '0.8rem', borderBottom: '1px solid var(--border)' }}>
                          <th style={{ padding: '0.75rem 1rem' }}>Time</th>
                          <th style={{ padding: '0.75rem 1rem' }}>Course</th>
                          <th style={{ padding: '0.75rem 1rem' }}>Room</th>
                          <th style={{ padding: '0.75rem 1rem' }}>Instructor</th>
                        </tr>
                      </thead>
                      <tbody>
                        {dayClasses.map((item, idx) => (
                          <tr key={idx} style={{ borderBottom: '1px solid rgba(255,255,255,0.03)' }}>
                            <td style={{ padding: '1rem', fontWeight: 600, color: 'var(--accent)' }}>
                              {(item.time || item.time_slot).split(' ').slice(1).join(' ')}
                            </td>
                            <td style={{ padding: '1rem' }}>
                              <div style={{ fontWeight: 600 }}>{item.code || item.course_code}</div>
                              <div style={{ fontSize: '0.75rem', color: 'var(--text-dim)' }}>{item.section || item.section_name}</div>
                            </td>
                            <td style={{ padding: '1rem' }}>{item.room || item.room_id}</td>
                            <td style={{ padding: '1rem', color: 'var(--text-dim)' }}>{item.instructor}</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  ) : (
                    <div style={{ padding: '1.5rem', textAlign: 'center', color: 'var(--text-dim)', fontSize: '0.9rem', border: '1px dashed var(--border)', borderRadius: '8px', marginTop: '0.5rem' }}>
                      No scheduled sessions for {day}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
}

function TabButton({ active, onClick, icon, label }: any) {
    return (
        <button 
            onClick={onClick}
            style={{
                display: 'flex',
                alignItems: 'center',
                gap: '0.5rem',
                padding: '0.5rem 1rem',
                borderRadius: '6px',
                border: 'none',
                cursor: 'pointer',
                fontSize: '0.875rem',
                backgroundColor: active ? 'var(--primary)' : 'transparent',
                color: active ? 'white' : 'var(--text-dim)',
                transition: 'all 0.2s'
            }}
        >
            {icon}
            {label}
        </button>
    )
}

