type CapacityViolation = {
  section_name: string;
  room_id: string;
  room_capacity: number;
  student_count: number;
  time_slot: string;
};

type MismatchViolation = {
  section_name: string;
  course_code: string;
  course_type: string;
  room_id: string;
  room_type: string;
  time_slot: string;
};

type ByodViolation = {
  section_name: string;
  room_id: string;
  time_slot: string;
  byod_students: number;
