        const byodStudents = studentIds.filter((sid) => Boolean(studentById[sid]?.is_byod)).length;
        if (byodStudents > 0) {
          byodViolations.push({
            section_name: a.section_name,
            room_id: a.room_id,
            time_slot: a.time_slot,
            byod_students: byodStudents
          });
        }
      }
    }

